SELECT COUNT(*) AS total_participacoes FROM lattes_p_banca pb JOIN lattes_banca b ON pb.fk_banca = b.pk JOIN servidor s ON pb.fk_siape = s.pk_siape WHERE LOWER(s.genero) = LOWER('masculino') AND LOWER(s.area_ingresso) LIKE LOWER('%engenharia civil%') AND LOWER(s.campus_atual) LIKE LOWER('%uruacu%') AND b.ano >= CAST(strftime('%Y', 'now') AS INTEGER) - 5 AND LOWER(b.natureza) LIKE LOWER('%gradua%')